import { useEffect, useMemo, useState } from 'react';
import type { SelectOption } from '@linm-soft/common-components';
import { voucherInitService, type ErpFormInitData } from '../services/voucherInit/endpoint';

const EMPTY: SelectOption[] = [];
const toOpts = (items?: FormOption[]): SelectOption[] =>
  (items ?? []).map(o => ({ value: o.value, label: o.label }));

type FormOption = { value: string; label: string };

export function useVoucherInitData(formName: string) {
  const [data, setData] = useState<ErpFormInitData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const timer = setTimeout(() => {
      if (cancelled) return;
      voucherInitService
        .getInitData(formName)
        .then(d => { if (!cancelled) setData(d); })
        .catch(() => { /* non-blocking — empty dropdowns */ })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [formName]);

  const materialGroupOptions = useMemo(() => toOpts(data?.materialGroupOptions), [data?.materialGroupOptions]);
  const partnerGroupOptions = useMemo(() => toOpts(data?.partnerGroupOptions), [data?.partnerGroupOptions]);
  const unitOptions = useMemo(() => toOpts(data?.unitOptions), [data?.unitOptions]);
  const taxRateOptions = useMemo(() => toOpts(data?.taxRateOptions), [data?.taxRateOptions]);
  const currencyOptions = useMemo(() => toOpts(data?.currencyOptions), [data?.currencyOptions]);
  const warehouseOptions = useMemo(() => toOpts(data?.warehouseOptions), [data?.warehouseOptions]);
  const departmentOptions = useMemo(() => toOpts(data?.departmentOptions), [data?.departmentOptions]);
  const voucherStatusOptions = useMemo(() => toOpts(data?.voucherStatusOptions), [data?.voucherStatusOptions]);
  const purchaseInvoiceTypeOptions = useMemo(
    () => toOpts(data?.purchaseInvoiceTypeOptions),
    [data?.purchaseInvoiceTypeOptions],
  );
  const processingLevelOptions = useMemo(
    () => toOpts(data?.processingLevelOptions),
    [data?.processingLevelOptions],
  );
  const receiptKindOptions = useMemo(() => toOpts(data?.receiptKindOptions), [data?.receiptKindOptions]);
  const customerGroupOptions = useMemo(() => toOpts(data?.customerGroupOptions), [data?.customerGroupOptions]);

  return {
    loading,
    materialGroupOptions,
    partnerGroupOptions,
    unitOptions,
    taxRateOptions,
    currencyOptions,
    warehouseOptions,
    departmentOptions,
    voucherStatusOptions,
    purchaseInvoiceTypeOptions,
    processingLevelOptions,
    defaultProcessingLevel: data?.defaultProcessingLevel,
    receiptKindOptions,
    customerGroupOptions,
    raw: data,
  };
}
